from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a city (or related entities) into a single fluent sentence."""
    if not triples:
        return ""

    # Find the main city subject (appears most frequently as subject)
    subject_counts = {}
    for triple in triples:
        subject_counts[triple.subject] = subject_counts.get(triple.subject, 0) + 1
    main_subject = max(subject_counts, key=subject_counts.get)

    # Separate triples by subject
    main_triples = [t for t in triples if t.subject == main_subject]
    other_triples = [t for t in triples if t.subject != main_subject]

    # Build clause for main subject
    main_clauses = []
    for triple in main_triples:
        s, p, o = triple.subject, triple.predicate, triple.object
        if p == "country":
            main_clauses.append(f"{s} is located in {o}")
        elif p == "isPartOf":
            main_clauses.append(f"{s} is part of {o}")
        elif p == "leader":
            main_clauses.append(f"{s} is led by {o}")
        elif p == "leaderTitle":
            main_clauses.append(f"{s} has a {o}")
        elif p == "populationTotal":
            main_clauses.append(f"{s} has a population of {o}")
        elif p == "areaTotal":
            main_clauses.append(f"{s} covers a total area of {o}")
        elif p == "areaOfLand":
            main_clauses.append(f"{s} has a land area of {o}")
        elif p == "areaOfWater":
            main_clauses.append(f"{s} has a water area of {o}")
        elif p == "elevationAboveTheSeaLevel":
            main_clauses.append(f"{s} sits at an elevation of {o} above sea level")
        elif p == "populationDensity":
            main_clauses.append(f"{s} has a population density of {o}")
        elif p == "populationMetro":
            main_clauses.append(f"{s} has a metropolitan population of {o}")
        elif p == "postalCode":
            main_clauses.append(f"{s} uses postal codes {o}")
        elif p == "areaCode":
            main_clauses.append(f"{s} uses area codes {o}")
        elif p == "utcOffset":
            main_clauses.append(f"{s} observes UTC offset {o}")
        elif p == "timeZone":
            main_clauses.append(f"{s} is in the {o} time zone")
        elif p == "language":
            main_clauses.append(f"the language spoken in {s} is {o}")
        elif p == "demonym":
            main_clauses.append(f"people from {s} are called {o}")
        elif p == "ethnicGroup":
            main_clauses.append(f"{s} includes {o} as an ethnic group")
        elif p == "type":
            main_clauses.append(f"{s} is a {o}")
        elif p == "governmentType":
            main_clauses.append(f"{s} has a {o}")
        elif p == "capital":
            main_clauses.append(f"{s}'s capital is {o}")
        elif p == "state":
            main_clauses.append(f"{s} is in the state of {o}")
        elif p == "largestCity":
            main_clauses.append(f"the largest city in {s} is {o}")
        elif p == "countySeat":
            main_clauses.append(f"the county seat of {s} is {o}")
        elif p == "headquarter":
            main_clauses.append(f"{s}'s headquarters is at {o}")
        elif p == "location":
            main_clauses.append(f"{s} is located at {o}")
        elif p == "chairperson":
            main_clauses.append(f"{s}'s chairperson is {o}")
        else:
            main_clauses.append(f"{s} {p} {o}")

    # Build clauses for other subjects (for context)
    other_clauses = []
    for triple in other_triples:
        s, p, o = triple.subject, triple.predicate, triple.object
        if p == "country":
            other_clauses.append(f"{o} is the country of {s}")
        elif p == "capital":
            other_clauses.append(f"{o} is the capital of {s}")
        elif p == "language":
            other_clauses.append(f"{o} is the language of {s}")
        elif p == "ethnicGroup":
            other_clauses.append(f"{o} is an ethnic group in {s}")
        elif p == "headquarter":
            other_clauses.append(f"{o} is the headquarters of {s}")
        elif p == "isPartOf":
            other_clauses.append(f"{s} is part of {o}")
        else:
            other_clauses.append(f"{s} {p} {o}")

    # Combine all clauses into one sentence
    all_clauses = main_clauses + other_clauses
    if not all_clauses:
        return ""

    # Capitalize first clause
    all_clauses[0] = all_clauses[0][0].upper() + all_clauses[0][1:]

    # Join with appropriate connectors
    if len(all_clauses) == 1:
        sentence = all_clauses[0] + "."
    elif len(all_clauses) == 2:
        sentence = f"{all_clauses[0]} and {all_clauses[1]}."
    else:
        sentence_parts = [all_clauses[0]]
        for i, clause in enumerate(all_clauses[1:], 1):
            if i == len(all_clauses) - 1:
                sentence_parts.append(f", and {clause}")
            else:
                sentence_parts.append(f", {clause}")
        sentence = " ".join(sentence_parts) + "."

    return sentence

# EVOLVE-BLOCK-END
